ecall_v1 = TextObject(bs_BA="Audi connect hitni poziv", cs_CZ="Nouzové volání Audi connect", da_DK="Audi connect Nødopkald", de_DE="Audi connect Notruf", el_GR="Κλήση ανάγκης Audi connect", en_GB="Audi connect emergency call", es_ES="Llamada de emergencia Audi connect", fi_FI="Audi connect -hätäpuhelu", fr_FR="Appel d'urgence Audi connect", hr_HR="Audi connect poziv u nuždi", hu_HU="Audi connect segélyhívás", it_IT="Chiamata d'emergenza Audi connect", nl_NL="Audi connect noodoproep", no_NO="Audi connect nødanrop", pl_PL="Połączenie alarmowe ​Audi connect", pt_PT="Chamada de emergência Audi connect", ro_RO="Apel de urgență Audi connect", ru_RU="Экстренный вызов Audi connect", sk_SK="Núdzové volanie Audi connect", sl_SI="Klic v sili Audi connect", sr_RS="Audi connect poziv u slučaju opasnosti", sv_SE="Audi connect-nödsamtal", tr_TR="Audi connect acil çağrı", uk_UA="Екстрений виклик Audi connect")
